from collections import defaultdict

def solve_crossword(grid, words):
    if not grid:
        return [] if not words else None
    rows = len(grid)
    cols = len(grid[0])
    board = [list(row) for row in grid]

    slots = []

    for r in range(rows):
        c = 0
        while c < cols:
            if board[r][c] != '#':
                start = c
                while c < cols and board[r][c] != '#':
                    c += 1
                if c - start >= 2:
                    slots.append([(r, start + i) for i in range(c - start)])
            else:
                c += 1

    for c in range(cols):
        r = 0
        while r < rows:
            if board[r][c] != '#':
                start = r
                while r < rows and board[r][c] != '#':
                    r += 1
                if r - start >= 2:
                    slots.append([(start + i, c) for i in range(r - start)])
            else:
                r += 1

    if len(slots) != len(words):
        return None

    if not slots:
        return [''.join(row) for row in board]

    used = [False] * len(words)

    wbl = defaultdict(list)
    for i, w in enumerate(words):
        wbl[len(w)].append(i)

    def can_place(slot, word):
        for (r, c), ch in zip(slot, word):
            if board[r][c] != '.' and board[r][c] != ch:
                return False
        return True

    def place(slot, word):
        old = []
        for (r, c), ch in zip(slot, word):
            old.append(board[r][c])
            board[r][c] = ch
        return old

    def unplace(slot, old):
        for (r, c), ch in zip(slot, old):
            board[r][c] = ch

    def backtrack(idx):
        if idx == len(slots):
            return True
        slot = slots[idx]
        for i in wbl.get(len(slot), []):
            if not used[i] and can_place(slot, words[i]):
                old = place(slot, words[i])
                used[i] = True
                if backtrack(idx + 1):
                    return True
                used[i] = False
                unplace(slot, old)
        return False

    if backtrack(0):
        return [''.join(row) for row in board]
    return None
